graphql.query:
{
    orders
        {
            id
            idempotency_key
            user_id
            delivery_address
            order_status
            created_at
            updated_at
            user {
                id
                first_name
                last_name
                address
                phone_number
                post_code
            }
            orderItems {
                id
                price_at_purchase
                quantity
                product_id
                product {
                    id
                    category_id
                    name
                    quantity
                }
            }
        }
}

query ordersFiltered($filter: OrdersFilterInput!, $ordersPaginationInput: OrdersPaginationInput!)
{
    ordersFiltered( filter: $filter, ordersPaginationInput: $ordersPaginationInput )
        {
            orders {
                id
                idempotency_key
                user_id
                delivery_address
                order_status
                created_at
                updated_at
                user {
                    id
                    first_name
                    last_name
                    address
                    phone_number
                    post_code
                }
                orderItems {
                    id
                    price_at_purchase
                    quantity
                    product_id
                    product {
                        id
                        category_id
                        name
                        quantity
                    }
                }
        }
        cursor {
            createdAt
            idTieBreaker
        }
        countOfPages
    }
}

